     1→/**
     2→ * Metrics Collector — Comprehensive infrastructure monitoring.
     3→ *
     4→ * Collects: server metrics (CPU, memory, uptime, active connections),
     5→ * database metrics (size, pool, query stats, slow queries),
     6→ * API metrics (request counts, error rates, latency percentiles, req/min),
     7→ * user/interview session metrics (practice/mock, completed/abandoned).
     8→ *
     9→ * Exposed via /api/admin/metrics endpoint.
    10→ */
    11→
    12→const os = require('os');
    13→const pool = require('./db');
    14→const { SERVER_START_TIME } = require('./activity-logger');
    15→
    16→// ─── Active HTTP Connection Tracking ─────────────────────────
    17→let activeHttpConnections = 0;
    18→
    19→function trackConnection(socket) {
    20→  activeHttpConnections++;
    21→  socket.on('close', () => { activeHttpConnections--; });
    22→}
    23→
    24→function setHttpServer(server) {
    25→  server.on('connection', trackConnection);
    26→}
    27→
    28→// ─── Request Metrics (in-memory, rolling window) ───────────────
    29→const REQUEST_WINDOW_MS = 60 * 60 * 1000; // 1 hour rolling window
    30→
    31→class RequestMetrics {
    32→  constructor() {
    33→    this.requests = [];       // { timestamp, method, path, status, duration }
    34→    this.totalRequests = 0;
    35→    this.totalErrors = 0;
    36→    this.endpointCounts = {};  // { path: { total, errors, durations[] } }
    37→  }
    38→
    39→  record(method, path, status, duration) {
    40→    const now = Date.now();
    41→    this.requests.push({ timestamp: now, method, path, status, duration });
    42→    this.totalRequests++;
    43→    if (status >= 400) this.totalErrors++;
    44→
    45→    // Per-endpoint tracking
    46→    const key = `${method} ${path}`;
    47→    if (!this.endpointCounts[key]) {
    48→      this.endpointCounts[key] = { total: 0, errors: 0, durations: [] };
    49→    }
    50→    this.endpointCounts[key].total++;
    51→    if (status >= 400) this.endpointCounts[key].errors++;
    52→    this.endpointCounts[key].durations.push(duration);
    53→
    54→    // Keep only last 1000 durations per endpoint
    55→    if (this.endpointCounts[key].durations.length > 1000) {
    56→      this.endpointCounts[key].durations = this.endpointCounts[key].durations.slice(-500);
    57→    }
    58→
    59→    // Prune old entries every 100 requests
    60→    if (this.requests.length % 100 === 0) {
    61→      this._prune(now);
    62→    }
    63→  }
    64→
    65→  _prune(now) {
    66→    const cutoff = now - REQUEST_WINDOW_MS;
    67→    this.requests = this.requests.filter(r => r.timestamp >= cutoff);
    68→  }
    69→
    70→  getPercentile(durations, pct) {
    71→    if (durations.length === 0) return 0;
    72→    const sorted = [...durations].sort((a, b) => a - b);
    73→    const idx = Math.ceil((pct / 100) * sorted.length) - 1;
    74→    return sorted[Math.max(0, idx)];
    75→  }
    76→
    77→  getSummary() {
    78→    const now = Date.now();
    79→    this._prune(now);
    80→
    81→    // Requests in last hour
    82→    const recentRequests = this.requests;
    83→    const recentErrors = recentRequests.filter(r => r.status >= 400);
    84→    const durations = recentRequests.map(r => r.duration).filter(d => d != null);
    85→
    86→    // Requests per minute (last 60 seconds)
    87→    const oneMinuteAgo = now - 60000;
    88→    const lastMinuteRequests = recentRequests.filter(r => r.timestamp >= oneMinuteAgo);
    89→
    90→    // Top endpoints by traffic
    91→    const topEndpoints = Object.entries(this.endpointCounts)
    92→      .map(([path, data]) => ({
    93→        path,
    94→        total: data.total,
    95→        errors: data.errors,
    96→        errorRate: data.total > 0 ? ((data.errors / data.total) * 100).toFixed(1) : '0.0',
    97→        p50: this.getPercentile(data.durations, 50),
    98→        p95: this.getPercentile(data.durations, 95),
    99→        p99: this.getPercentile(data.durations, 99),
   100→      }))
   101→      .sort((a, b) => b.total - a.total)
   102→      .slice(0, 20);
   103→
   104→    return {
   105→      hourly: {
   106→        requests: recentRequests.length,
   107→        errors: recentErrors.length,
   108→        errorRate: recentRequests.length > 0
   109→          ? ((recentErrors.length / recentRequests.length) * 100).toFixed(1)
   110→          : '0.0',
   111→      },
   112→      cumulative: {
   113→        totalRequests: this.totalRequests,
   114→        totalErrors: this.totalErrors,
   115→        errorRate: this.totalRequests > 0
   116→          ? ((this.totalErrors / this.totalRequests) * 100).toFixed(1)
   117→          : '0.0',
   118→      },
   119→      latency: {
   120→        p50: this.getPercentile(durations, 50),
   121→        p95: this.getPercentile(durations, 95),
   122→        p99: this.getPercentile(durations, 99),
   123→        avg: durations.length > 0 ? Math.round(durations.reduce((a, b) => a + b, 0) / durations.length) : 0,
   124→      },
   125→      requestsPerMinute: lastMinuteRequests.length,
   126→      topEndpoints,
   127→    };
   128→  }
   129→}
   130→
   131→const requestMetrics = new RequestMetrics();
   132→
   133→// ─── Metrics Collection Functions ─────────────────────────────
   134→
   135→/**
   136→ * Get server metrics (CPU, memory, uptime, active connections).
   137→ */
   138→function getServerMetrics() {
   139→  const uptime = Math.floor((Date.now() - SERVER_START_TIME) / 1000);
   140→  const memUsage = process.memoryUsage();
   141→  const totalMem = os.totalmem();
   142→  const freeMem = os.freemem();
   143→  const cpus = os.cpus();
   144→
   145→  // Calculate CPU usage from cpus
   146→  let totalIdle = 0;
   147→  let totalTick = 0;
   148→  for (const cpu of cpus) {
   149→    for (const type of Object.keys(cpu.times)) {
   150→      totalTick += cpu.times[type];
   151→    }
   152→    totalIdle += cpu.times.idle;
   153→  }
   154→  const cpuUsage = ((1 - totalIdle / totalTick) * 100).toFixed(1);
   155→
   156→  return {
   157→    uptime,
   158→    uptimeFormatted: formatUptime(uptime),
   159→    activeConnections: activeHttpConnections,
   160→    cpu: {
   161→      usage: parseFloat(cpuUsage),
   162→      cores: cpus.length,
   163→      model: cpus[0]?.model || 'unknown',
   164→    },
   165→    memory: {
   166→      heapUsed: memUsage.heapUsed,
   167→      heapTotal: memUsage.heapTotal,
   168→      rss: memUsage.rss,
   169→      external: memUsage.external,
   170→      heapUsedMB: Math.round(memUsage.heapUsed / 1024 / 1024),
   171→      rssMB: Math.round(memUsage.rss / 1024 / 1024),
   172→      systemTotal: totalMem,
   173→      systemFree: freeMem,
   174→      systemUsedPct: ((1 - freeMem / totalMem) * 100).toFixed(1),
   175→    },
   176→    platform: {
   177→      node: process.version,
   178→      os: `${os.type()} ${os.release()}`,
   179→      arch: os.arch(),
   180→      hostname: os.hostname(),
   181→    },
   182→  };
   183→}
   184→
   185→function formatUptime(seconds) {
   186→  const days = Math.floor(seconds / 86400);
   187→  const hours = Math.floor((seconds % 86400) / 3600);
   188→  const minutes = Math.floor((seconds % 3600) / 60);
   189→  if (days > 0) return `${days}d ${hours}h ${minutes}m`;
   190→  if (hours > 0) return `${hours}h ${minutes}m`;
   191→  return `${minutes}m`;
   192→}
   193→
   194→/**
   195→ * Get database metrics (size, connections, pool, query stats).
   196→ */
   197→async function getDatabaseMetrics() {
   198→  try {
   199→    const queryStats = pool.getQueryStats ? pool.getQueryStats() : { totalQueries: 0, slowQueries: 0, queriesPerMinute: 0 };
   200→
   201→    const [sizeResult, connResult, tableResult] = await Promise.all([
   202→      pool.query("SELECT pg_database_size(current_database()) as size"),
   203→      pool.query("SELECT count(*) as count FROM pg_stat_activity WHERE state = 'active'"),
   204→      pool.query(`
   205→        SELECT relname as table_name, n_live_tup as row_count
   206→        FROM pg_stat_user_tables
   207→        ORDER BY n_live_tup DESC
   208→        LIMIT 15
   209→      `),
   210→    ]);
   211→
   212→    const dbSizeBytes = parseInt(sizeResult.rows[0]?.size || 0, 10);
   213→    const activeConns = parseInt(connResult.rows[0]?.count || 0, 10);
   214→    const poolTotal = pool.totalCount || 0;
   215→    const poolIdle = pool.idleCount || 0;
   216→    const poolWaiting = pool.waitingCount || 0;
   217→    const poolActive = poolTotal - poolIdle;
   218→
   219→    return {
   220→      sizeBytes: dbSizeBytes,
   221→      sizeMB: (dbSizeBytes / 1024 / 1024).toFixed(1),
   222→      activeConnections: activeConns,
   223→      poolTotal,
   224→      poolIdle,
   225→      poolWaiting,
   226→      poolUtilization: poolTotal > 0 ? ((poolActive / poolTotal) * 100).toFixed(1) : '0.0',
   227→      totalQueries: queryStats.totalQueries,
   228→      slowQueries: queryStats.slowQueries,
   229→      queriesPerMinute: queryStats.queriesPerMinute,
   230→      tables: tableResult.rows.map(r => ({
   231→        name: r.table_name,
   232→        rows: parseInt(r.row_count, 10),
   233→      })),
   234→    };
   235→  } catch (err) {
   236→    console.error('[metrics] Database metrics error:', err.message);
   237→    return { error: err.message };
   238→  }
   239→}
   240→
   241→/**
   242→ * Get user and interview metrics (with practice/mock + completed/abandoned breakdown).
   243→ */
   244→async function getUserMetrics() {
   245→  try {
   246→    const [
   247→      usersResult,
   248→      activeResult,
   249→      interviewsResult,
   250→      interviewsTodayResult,
   251→      activeSessionsResult,
   252→    ] = await Promise.all([
   253→      pool.query(`
   254→        SELECT
   255→          COUNT(*) as total,
   256→          COUNT(*) FILTER (WHERE role = 'candidate') as candidates,
   257→          COUNT(*) FILTER (WHERE role = 'recruiter') as recruiters
   258→        FROM users
   259→      `),
   260→      pool.query(`
   261→        SELECT COUNT(DISTINCT user_id) as active_today
   262→        FROM activity_log
   263→        WHERE created_at >= NOW() - INTERVAL '24 hours'
   264→        AND user_id IS NOT NULL
   265→      `).catch(() => ({ rows: [{ active_today: 0 }] })),
   266→      pool.query(`
   267→        SELECT
   268→          COUNT(*) as total,
   269→          COUNT(*) FILTER (WHERE status = 'completed') as completed,
   270→          COUNT(*) FILTER (WHERE status IN ('in-progress', 'pending')) as active,
   271→          COUNT(*) FILTER (WHERE status IN ('abandoned', 'cancelled')) as abandoned,
   272→          COUNT(*) FILTER (WHERE interview_type = 'practice') as practice,
   273→          COUNT(*) FILTER (WHERE interview_type = 'mock') as mock
   274→        FROM interviews
   275→      `),
   276→      pool.query(`
   277→        SELECT COUNT(*) as count
   278→        FROM interviews
   279→        WHERE created_at >= NOW() - INTERVAL '24 hours'
   280→      `),
   281→      pool.query(`
   282→        SELECT COUNT(*) as count FROM user_sessions WHERE expire > NOW()
   283→      `).catch(() => ({ rows: [{ count: 0 }] })),
   284→    ]);
   285→
   286→    const users = usersResult.rows[0];
   287→    const interviews = interviewsResult.rows[0];
   288→
   289→    return {
   290→      users: {
   291→        total: parseInt(users.total, 10),
   292→        candidates: parseInt(users.candidates, 10),
   293→        recruiters: parseInt(users.recruiters, 10),
   294→        activeToday: parseInt(activeResult.rows[0]?.active_today || 0, 10),
   295→      },
   296→      interviews: {
   297→        total: parseInt(interviews.total, 10),
   298→        completed: parseInt(interviews.completed || 0, 10),
   299→        active: parseInt(interviews.active || 0, 10),
   300→        today: parseInt(interviewsTodayResult.rows[0]?.count || 0, 10),
   301→        abandoned: parseInt(interviews.abandoned || 0, 10),
   302→        practice: parseInt(interviews.practice || 0, 10),
   303→        mock: parseInt(interviews.mock || 0, 10),
   304→      },
   305→      activeSessions: parseInt(activeSessionsResult.rows[0]?.count || 0, 10),
   306→    };
   307→  } catch (err) {
   308→    console.error('[metrics] User metrics error:', err.message);
   309→    return { error: err.message };
   310→  }
   311→}
   312→
   313→/**
   314→ * Get all metrics in one call (for dashboard).
   315→ */
   316→async function getAllMetrics() {
   317→  const [server, db, users] = await Promise.all([
   318→    getServerMetrics(),
   319→    getDatabaseMetrics(),
   320→    getUserMetrics(),
   321→  ]);
   322→
   323→  return {
   324→    timestamp: new Date().toISOString(),
   325→    server,
   326→    database: db,
   327→    api: requestMetrics.getSummary(),
   328→    users: users.users || {},
   329→    interviews: users.interviews || {},
   330→    activeSessions: users.activeSessions || 0,
   331→  };
   332→}
   333→
   334→/**
   335→ * Express middleware to record request metrics.
   336→ * Should be placed early in the middleware chain.
   337→ */
   338→function metricsMiddleware(req, res, next) {
   339→  if (req.path === '/health' || !req.path.startsWith('/api')) {
   340→    return next();
   341→  }
   342→
   343→  const start = Date.now();
   344→  res.on('finish', () => {
   345→    const duration = Date.now() - start;
   346→    // Normalize path: replace IDs with :id
   347→    const normalizedPath = req.path.replace(/\/\d+/g, '/:id');
   348→    requestMetrics.record(req.method, normalizedPath, res.statusCode, duration);
   349→  });
   350→  next();
   351→}
   352→
   353→module.exports = {
   354→  getAllMetrics,
   355→  getServerMetrics,
   356→  getDatabaseMetrics,
   357→  getUserMetrics,
   358→  requestMetrics,
