   244→/**
   245→ * Match a request to a business event.
   246→ * Returns { type, category } or null if no match (falls back to generic).
   247→ */
   248→function matchRouteEvent(method, path) {
   249→  for (const route of ROUTE_EVENT_MAP) {
   250→    if (route.method === method && route.pattern.test(path)) {
   251→      return { type: route.type, category: route.category };
   252→    }
   253→  }
   254→  return null;
   255→}
