   257→/**
   258→ * Express middleware that logs every API request as a meaningful business event.
   259→ * Maps route patterns to descriptive event types (e.g., 'application_submitted' instead of 'api_request').
   260→ * Attach after auth middleware so req.user is available.
   261→ */
   262→function requestLogger(req, res, next) {
   263→  const start = Date.now();
   264→
   265→  // Log on response finish
   266→  res.on('finish', () => {
   267→    // Skip health checks, static files, and admin polling endpoints
   268→    if (req.path === '/health' || !req.path.startsWith('/api')) return;
   269→    // Skip noisy admin polling (metrics, activity, modules, ai-health GET)
   270→    if (req.method === 'GET' && (
   271→      req.path === '/api/admin/metrics' ||
   272→      req.path === '/api/admin/activity' ||
   273→      req.path === '/api/admin/modules' ||
   274→      req.path === '/api/ai-health'
   275→    )) return;
   276→
   277→    const duration = Date.now() - start;
   278→    const isError = res.statusCode >= 400;
   279→    const matched = matchRouteEvent(req.method, req.path);
   280→
   281→    // Use matched event or fall back to generic
   282→    const eventType = isError ? (matched ? `${matched.type}_failed` : 'api_error') : (matched ? matched.type : 'api_request');
   283→    const category = isError ? 'error' : (matched ? matched.category : 'system');
   284→
   285→    logActivity({
   286→      type: eventType,
   287→      category,
   288→      severity: res.statusCode >= 500 ? 'error' : (res.statusCode >= 400 ? 'warning' : 'info'),
   289→      userId: req.user?.id,
   290→      userEmail: req.user?.email,
   291→      details: {
   292→        method: req.method,
   293→        path: req.path,
   294→        statusCode: res.statusCode,
   295→        duration,
   296→        ...(matched ? {} : {}), // matched events already have descriptive type
   297→      },
   298→      ip: req.ip,
   299→    });
   300→  });
   301→
   302→  next();
   303→}
