    52→// ─── CORE CHAT: Now with automatic multi-provider fallback ─────
    53→// Fallback chain: Anthropic → OpenAI → NIM Nemotron → NIM Kimi → NIM DeepSeek
    54→async function chat(message, options = {}) {
    55→  // Handle both string messages and arrays of message objects
    56→  let messages;
    57→  if (Array.isArray(message)) {
    58→    // Filter out system messages and extract them
    59→    const systemMessages = message.filter(m => m.role === 'system');
    60→    const nonSystemMessages = message.filter(m => m.role !== 'system');
    61→
    62→    // Use the first system message content as the system prompt if not already set
    63→    if (systemMessages.length > 0 && !options.system) {
    64→      options.system = systemMessages[0].content;
    65→    }
    66→
    67→    // Ensure messages have proper format (content must be string or array)
    68→    messages = nonSystemMessages.map(m => ({
    69→      role: m.role,
    70→      content: typeof m.content === 'string' ? m.content : String(m.content)
    71→    }));
    72→  } else {
    73→    // Simple string message
    74→    messages = [{ role: 'user', content: String(message) }];
    75→  }
    76→
    77→  // Ensure we have at least one message
    78→  if (messages.length === 0) {
    79→    messages = [{ role: 'user', content: 'Hello' }];
    80→  }
    81→
    82→  // Use the provider service with automatic fallback
    83→  return aiProvider.chatCompletion(messages, options);
    84→}
